var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_LEGACY_NULL_GUNTLET","text":{"KOREA":"버러지들이…… 젠장……!","JPN":"この雑魚どもが……！　くそ……！","ENG":"You little pests...! Dammit...!","TWN":"你們這些蟲子……該死……！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하아…… 하아……","JPN":"はぁ……はぁ……","ENG":"*Huff* *Huff*","TWN":"哈啊……哈啊……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"해치웠…… 으읍!!","JPN":"やっつけ……うぶっ！！","ENG":"I got he– MMMMPH!!","TWN":"我要除掉……呃呃！！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L10_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"고마해라, 플래그는 한 번으로 충분하다.","JPN":"やめとけ。フラグは1度で十分や。","ENG":"No. One foreshadowing is enough.","TWN":"可以了，到此為止。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"대, 대단해! 저 사람들이 최초 클리어 맞죠?!","JPN":"す、すごい！　クリアしたのはこの人たちが初めてですよね！？","ENG":"I-I can't believe it! They're the first to clear the quest, right?!","TWN":"太，太厲害了！那些人是第一次通關吧？！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L13_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"헉, 시, 시청자 수가 이렇게나……?","JPN":"ひっ！　し、視聴者数がこんなに……？","ENG":"Whoa...! So many viewers...!","TWN":"哇，觀，觀眾人數竟然這麼多……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"고생했다. 우리가 최초 클리어까지 해버렸네.","JPN":"お疲れさん。ウチらが初クリアタイトルまで取ってしもうたな。","ENG":"Good job. We're the first ones to clear the quest.","TWN":"辛苦了，我們竟然完成了首次通關。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"분명 니 랭킹에도 반영될 기다. 축하한다.","JPN":"きっとあんたのランキングにも反映されるはずや。おめでとさん。","ENG":"I'm sure it'll reflect your rank. Congrats.","TWN":"肯定會反應在你排名上的，恭喜你。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"훗, 내가 랭커가 되는 건 어차피 기정사실이잖아?","JPN":"ふっ、私がランカーになるのは既成事実のようなものだったしね！","ENG":"Hmph. It goes without saying that I'm going to become a top ranker.","TWN":"哼，我成為前段班是遲早的事，不是嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"선배! 나이트를 보스 몬스터로 구현한 거, 선배 맞죠?","JPN":"先輩！　ナイトをボスモンスターに具現化したのは先輩ですよね？","ENG":"Bora! You're the one who implemented Knight into a boss monster, right?","TWN":"前輩！把騎士製作成BOSS的是前輩吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"응…… 맞아.","JPN":"うん……そう。","ENG":"Yeah... That was me.","TWN":"嗯……沒錯。"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"원했었잖아…… 옛날에.","JPN":"望んでいたでしょ……昔に。","ENG":"You wanted it... a long time ago.","TWN":"在很久以前……你曾經想做的。"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그랬었죠. 어떻게 그게 가능했던 건가요?","JPN":"そうでしたね。どうやって叶えたんですか？","ENG":"I did. But how was that possible?","TWN":"是啊，你是怎麼做到的呢？"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아, 역시 관리국에 아는 분이 계신다던가?","JPN":"あ、やっぱり管理局に知り合いがいるんですか？","ENG":"Oh, is there someone you know within the Administration?","TWN":"啊，果然在管理局有認識的人嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"미안해…… 말해줄 수 없어. 지금은.","JPN":"ごめん……言えない。今は。","ENG":"I'm sorry... I can't tell you that. Right now.","TWN":"對不起……現在不能告訴你。"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아하하, 괜찮아요. 선배는 언제나 절 깜짝 놀라게 한다니까요?","JPN":"あはは、大丈夫です。先輩にはいつも驚かされてばかりですね。","ENG":"Ah hah hah, it's fine. You always find ways to surprise me, you know that?","TWN":"哈哈哈，沒關係的。前輩總是讓我大吃一驚呢？"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"헤헷, 그렇다면 저도 가만히 있을 순 없어요!","JPN":"えへへ、私もこんなことしてる場合じゃありません！","ENG":"Hehe, then I can't just stand around and do nothing!","TWN":"哼哼，如果是這樣，我也不能袖手旁觀！"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L33_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"어디 가는 거야……?","JPN":"どこに行くの……？","ENG":"Where are you going...?","TWN":"你去哪……？"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"마침 다음 주에 카운터즈 레거시의 업데이트 방송이 있잖아요","JPN":"ちょうど来週、カウンターズ・レガシーのアップデート配信があるじゃないですか。","ENG":"Next week is Counters Legacy's update livestream.","TWN":"正好下週有制裁者的遺產的更新直播。"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그때까지 선배를 깜짝 놀랄만한 기획을 준비해 오겠어요!","JPN":"それまでに先輩をびっくりさせるような企画を用意します！","ENG":"I'm going to prepare something that will surprise you by then!","TWN":"到那時，我會準備一個讓前輩大吃一驚的企劃！"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"대단한 열정이네. 어떤 기획을 하시려는 걸까?","JPN":"すごい熱情ね。どんな企画を持ってきてくれるのかしら。","ENG":"How passionate. I wonder what she'll come up with.","TWN":"真是熱情洋溢啊。你打算策劃什麼呢？"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"역시 선배는 정말 대단해.","JPN":"やっぱり先輩はすごい。","ENG":"I knew it. Bora is really amazing.","TWN":"前輩你果然很厲害。"},"stage":{"bg":"CORRIDOR_05","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"관리국에서 극비 정보로 다루는 나이트를 보스로 쓸 생각을 하다니……!","JPN":"管理局でも極秘情報として扱われているナイトのデータでボスを作るという発想……！","ENG":"The Administration treats Knight as confidential information. I can't believe she would use Knight as a boss monster...!","TWN":"竟然想到把管理局視為機密的克隆·騎士做成BOSS……！"},"stage":{"bg":"CORRIDOR_05","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그렇다면 나도 지고 있을 수만은 없지. 선배를 깜짝 놀라게 하는 거야!","JPN":"私も負けてはいられない。先輩をびっくりさせるんだ！","ENG":"I can't let her best me. I'm going to prepare something that'll knock her socks off!","TWN":"既然如此，我也不能輸。我要讓前輩大吃一驚！"},"stage":{"bg":"CORRIDOR_05","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L48_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"푸, 품절이라고요……?","JPN":"し、品切れですか……？","ENG":"S-sold out...?","TWN":"賣完了……？"},"stage":{"bg":"CITY_CENTER2","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CONSOLE_LEGACY_NULL_EXTRA","text":{"KOREA":"정말 죄송합니다. 기기를 구매하시려면 최소 일주일 전에는 예약하셔야 해요.","JPN":"大変申し訳ございません。機器をご購入いただくには、最低でも1週間前には予約していただく必要がございまして。","ENG":"I'm terribly sorry, but you'll have to pre-order at least a week in advance to purchase the console.","TWN":"真的很抱歉。如果你想購買機子，至少需要提前一週預訂。"},"stage":{"bg":"CITY_CENTER2","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"그, 그렇습니까……? 그럼 이날로 부탁드리겠습니다.","JPN":"そ、そうですか……じゃあ、この日でお願いします。","ENG":"I-is that so...? Then, I'd like to buy one at this date.","TWN":"是，是這樣嗎……？那就拜託你今天幫我預訂了。"},"stage":{"bg":"CITY_CENTER2","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CONSOLE_LEGACY_NULL_EXTRA","text":{"KOREA":"네. 그럼 가격표 보시고 기종을 골라주시면 됩니다.","JPN":"かしこまりました。では価格表をご覧いただき、機種をお選びください。","ENG":"Certainly. Then, please look at the prices and pick out a model.","TWN":"好的。請看價格表選擇機型。"},"stage":{"bg":"CITY_CENTER2","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"헛, 이 액수는, 지금 당장 지불하기엔 부담스러운데…….","JPN":"はっ、この値段は……今すぐ払うには少し負担が……","ENG":"Whoa...! That's... a bit more than I can afford right now...","TWN":"哎，這個價格，現在支付有點吃力啊……"},"stage":{"bg":"CITY_CENTER2","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"혹시…… 외상은 안 되겠습니까……?\xA0","JPN":"あの……ツケでお願いできませんか……？\xA0","ENG":"Is there... anyway I can pay for it later...?\xA0","TWN":"那個……可以賒帳嗎……？"},"stage":{"bg":"CITY_CENTER2","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};